INSERT INTO quiz_questions (quiz_id, question_text, question_type, options, correct_answer, explanation)
VALUES
('e9ce9c96-86e6-48bb-94ea-6fd0c7edfb64', 'Trong bài thi IELTS Writing Task 1 (Line Graph), cụm từ ''An upward trend'' miêu tả xu hướng nào?', 'multiple_choice', '["Dữ liệu giữ nguyên không đổi.","Dữ liệu có xu hướng tăng lên trong một khoảng thời gian.","Dữ liệu giảm xuống nhanh chóng.","Dữ liệu dao động liên tục."]', 'Dữ liệu có xu hướng tăng lên trong một khoảng thời gian.', 'Đây là cụm từ cơ bản và cực kỳ quan trọng để mô tả xu hướng tổng quan (Overview) của một biểu đồ đường đi lên.'),
('e9ce9c96-86e6-48bb-94ea-6fd0c7edfb64', 'Động từ ''Peak at'' trong biểu đồ đường được dùng để chỉ mốc nào?', 'multiple_choice', '["Điểm xuất phát ban đầu của dữ liệu.","Điểm thấp nhất của biểu đồ (đáy).","Chạm đến điểm cao nhất, đỉnh cao nhất của biểu đồ trước khi bắt đầu đi xuống.","Điểm giao nhau của hai đường đồ thị."]', 'Chạm đến điểm cao nhất, đỉnh cao nhất của biểu đồ trước khi bắt đầu đi xuống.', 'Ví dụ: ''The number of visitors peaked at 5,000 in July'' (Lượng khách chạm đỉnh 5,000 vào tháng 7).'),
('e9ce9c96-86e6-48bb-94ea-6fd0c7edfb64', 'Cụm từ ''Fluctuate wildly'' được sử dụng khi đường đồ thị có hình dáng như thế nào?', 'multiple_choice', '["Tăng một cách nhẹ nhàng và ổn định.","Dao động, lên xuống liên tục với biên độ lớn và không thể hiện một xu hướng tăng giảm rõ rệt nào.","Đi ngang thẳng tắp.","Rơi tự do tạo thành góc vuông."]', 'Dao động, lên xuống liên tục với biên độ lớn và không thể hiện một xu hướng tăng giảm rõ rệt nào.', '''Fluctuate'' (dao động) là từ vựng đắt giá để miêu tả sự bất ổn định của số liệu trong một giai đoạn nhất định.'),
('06035948-da93-4445-9cf0-267865bcd31f', 'Khi phân tích biểu đồ Tròn (Pie Chart), danh từ nào là thích hợp nhất để nói về các phần được chia ra (tính bằng %)?', 'multiple_choice', '["The speed","The distance","The proportion / The percentage","The length"]', 'The proportion / The percentage', 'Pie chart biểu diễn tỷ lệ phần trăm của một tổng thể. Dùng từ ''The proportion of'' hoặc ''The percentage of'' là bắt buộc.'),
('06035948-da93-4445-9cf0-267865bcd31f', 'Thay vì viết ''50%'', bạn có thể dùng cụm từ phân số nào để bài viết đa dạng hơn?', 'multiple_choice', '["A quarter","Exactly half","A third","A minority"]', 'Exactly half', 'Chuyển đổi linh hoạt giữa Tỷ lệ % (50%) và Phân số (A half / One in two) là kỹ năng ghi điểm Lexical Resource trong Task 1.'),
('06035948-da93-4445-9cf0-267865bcd31f', 'Trạng từ ''Respectively'' (Tương ứng, theo thứ tự lần lượt) được sử dụng thế nào trong câu văn Task 1?', 'multiple_choice', '["Dùng ở đầu câu để mở bài.","Dùng ở cuối câu để gán chính xác các số liệu với các chủ thể đã liệt kê phía trước (Ví dụ: A and B were 10% and 20% respectively).","Dùng để chỉ sự tôn trọng đối với người đọc.","Dùng để kết thúc bài viết."]', 'Dùng ở cuối câu để gán chính xác các số liệu với các chủ thể đã liệt kê phía trước (Ví dụ: A and B were 10% and 20% respectively).', 'Đây là công cụ gom ý (grouping) thần thánh, giúp bạn trình bày 2-3 số liệu trong cùng một câu một cách rành mạch mà không bị lặp cấu trúc.'),
('d4f5f626-374d-4f12-9a8c-ff77be04b2b2', 'Lỗi sai nguy hiểm nhất khi mô tả một Bảng số liệu (Table) có quá nhiều thông tin là gì?', 'multiple_choice', '["Viết bài bằng bút bi đỏ.","Cố gắng liệt kê và viết ra TẤT CẢ mọi con số có trong bảng một cách máy móc như một cái máy tính.","Chỉ mô tả những con số lớn nhất và nhỏ nhất.","Viết phần Overview (Tổng quan)."]', 'Cố gắng liệt kê và viết ra TẤT CẢ mọi con số có trong bảng một cách máy móc như một cái máy tính.', 'IELTS yêu cầu bạn ''Summarize'' (Tóm tắt) bằng cách ''selecting and reporting the main features'' (chọn lọc tính năng chính). Đưa toàn bộ số liệu vào bài sẽ khiến bạn bị trừ điểm Task Achievement vì không biết chọn lọc.'),
('d4f5f626-374d-4f12-9a8c-ff77be04b2b2', 'Trong dạng bài Mixed Charts (Biểu đồ kết hợp, ví dụ 1 Pie chart + 1 Bar chart), phần Overview (Tổng quan) của bạn cần phải làm gì?', 'multiple_choice', '["Chỉ viết về biểu đồ có nhiều hình ảnh hơn.","Chỉ viết về Bar chart.","Bắt buộc phải tóm tắt xu hướng chính hoặc đặc điểm nổi bật nhất của CẢ HAI biểu đồ.","Giải thích tại sao họ lại gộp hai biểu đồ lại."]', 'Bắt buộc phải tóm tắt xu hướng chính hoặc đặc điểm nổi bật nhất của CẢ HAI biểu đồ.', 'Bỏ sót một trong hai biểu đồ ở phần Overview sẽ khiến bạn không bao giờ đạt được Band 7.0+ ở tiêu chí Task Achievement.'),
('d4f5f626-374d-4f12-9a8c-ff77be04b2b2', 'Khi hai biểu đồ trong bài Mixed Charts có mối liên hệ với nhau, kỹ thuật nào giúp bài viết của bạn ăn điểm cao?', 'multiple_choice', '["Viết hai đoạn văn hoàn toàn rời rạc.","Tìm ra sự Tương quan (Correlation) hoặc điểm giao thoa giữa dữ liệu của biểu đồ 1 và biểu đồ 2 để đề cập (nếu có thể).","Cộng dồn số liệu của hai biểu đồ lại.","Bỏ qua biểu đồ thứ hai."]', 'Tìm ra sự Tương quan (Correlation) hoặc điểm giao thoa giữa dữ liệu của biểu đồ 1 và biểu đồ 2 để đề cập (nếu có thể).', 'Sự so sánh chéo (Cross-comparison) giữa hai biểu đồ cho thấy khả năng phân tích dữ liệu đa chiều của bạn.'),
('0763e16d-2e52-4fc7-a93b-e8d9afd81190', 'Trong dạng bài Process (Quy trình sản xuất), tại sao ''Câu bị động'' (Passive Voice) lại là điểm ngữ pháp bắt buộc?', 'multiple_choice', '["Vì nó làm bài viết dài hơn.","Vì trong quy trình công nghiệp, trọng tâm nằm ở CÁC BƯỚC ĐƯỢC THỰC HIỆN lên vật thể, chứ người thực hiện (công nhân) không quan trọng. (Ví dụ: The tea leaves are picked).","Vì câu chủ động bị cấm dùng trong IELTS.","Vì nó giúp câu văn có nhịp điệu hay hơn."]', 'Vì trong quy trình công nghiệp, trọng tâm nằm ở CÁC BƯỚC ĐƯỢC THỰC HIỆN lên vật thể, chứ người thực hiện (công nhân) không quan trọng. (Ví dụ: The tea leaves are picked).', 'Nếu bạn dùng ''Workers pick the tea leaves, then they dry them'', phong cách viết sẽ trở thành kể chuyện (informal). Dùng bị động ''are picked, are dried'' tạo ra sự khách quan học thuật.'),
('0763e16d-2e52-4fc7-a93b-e8d9afd81190', 'Khi miêu tả các bước liên tiếp nhau trong một Process, nhóm từ vựng (Sequencing words) nào sau đây là quan trọng nhất?', 'multiple_choice', '["I think, In my opinion, Personally.","First, Following this, Subsequently, Finally.","Because, So, Due to.","North, South, East, West."]', 'First, Following this, Subsequently, Finally.', 'Các từ chỉ trình tự thời gian (chronological order) đóng vai trò như dây xích liên kết các giai đoạn rời rạc trong hình vẽ thành một chuỗi quy trình mạch lạc.'),
('0763e16d-2e52-4fc7-a93b-e8d9afd81190', 'Khi mô tả sự thay đổi của một Bản đồ (Map) qua 2 mốc thời gian, nhóm từ vựng nào dùng để chỉ ''Sự xây dựng mới'' và ''Sự phá bỏ''?', 'multiple_choice', '["Increase, Decrease, Fluctuate.","Construct / Build / Erect (Xây mới) và Demolish / Knock down (Phá bỏ).","Read, Write, Listen.","Buy, Sell, Trade."]', 'Construct / Build / Erect (Xây mới) và Demolish / Knock down (Phá bỏ).', 'Việc sử dụng chính xác các động từ biến đổi không gian (Transformation verbs) là yếu tố quyết định điểm Vocabulary trong dạng Map.'),
('8269458d-2ef9-4510-a26a-193b52103b52', 'Trong IELTS General Training Task 1 (Thư cá nhân / Informal Letter), lời chào mở đầu và kết thúc nào là phù hợp nhất khi viết cho một người bạn thân?', 'multiple_choice', '["Dear Sir/Madam, / Yours faithfully,","To whom it may concern, / Best regards,","Dear [Tên bạn], / Best wishes, hoặc Lots of love,","Hello Mr. Smith, / Yours sincerely,"]', 'Dear [Tên bạn], / Best wishes, hoặc Lots of love,', 'Trong văn phong thân mật (Informal), bạn phải dùng tên gọi trực tiếp (first name) và các lời kết thư ấm áp, không được dùng các cụm từ hành chính cứng nhắc.'),
('8269458d-2ef9-4510-a26a-193b52103b52', 'Việc sử dụng Contractions (dạng viết tắt như I''m, don''t, can''t) có được chấp nhận trong Thư cá nhân (Informal Letter) không?', 'multiple_choice', '["Tuyệt đối không, sẽ bị trừ điểm ngay.","Chỉ được dùng 1 lần duy nhất.","Hoàn toàn được chấp nhận và thậm chí ĐƯỢC KHUYẾN KHÍCH, vì nó thể hiện đúng giọng điệu thân mật, gần gũi của đời sống hàng ngày.","Được dùng nhưng phải viết hoa toàn bộ."]', 'Hoàn toàn được chấp nhận và thậm chí ĐƯỢC KHUYẾN KHÍCH, vì nó thể hiện đúng giọng điệu thân mật, gần gũi của đời sống hàng ngày.', 'Sử dụng ''I am not'' thay vì ''I''m not'' với bạn thân sẽ khiến bức thư nghe giống như robot hoặc đang giận dỗi. ''Tone'' (Giọng điệu) là tiêu chí cực quan trọng trong GT Task 1.'),
('8269458d-2ef9-4510-a26a-193b52103b52', 'Trong Thư cá nhân, sau phần chào hỏi, bạn nên mở đầu bức thư bằng câu nào để tạo sự tự nhiên?', 'multiple_choice', '["I am writing to formally request...","Hope you''re doing well! / It was great to hear from you last week.","Please be informed that...","According to the recent data..."]', 'Hope you''re doing well! / It was great to hear from you last week.', 'Những câu hỏi thăm sức khỏe hoặc nhắc lại kỷ niệm nhỏ là cách ''warm-up'' tiêu chuẩn trong giao tiếp thân mật trước khi đi vào nội dung chính.'),
('55d5d28f-5fb9-435e-9a97-af7723d80239', 'Thế nào là bối cảnh của một bức Thư bán trang trọng (Semi-formal Letter)?', 'multiple_choice', '["Viết cho một người bạn thời thơ ấu để rủ đi chơi.","Viết cho một người mà bạn BIẾT RÕ TÊN, có quan hệ xã giao hoặc công việc (ví dụ: Đồng nghiệp, Chủ nhà, Giáo viên, Hàng xóm) nhưng không thân thiết như bạn bè.","Viết cho Chủ tịch nước hoặc người đứng đầu tập đoàn chưa từng gặp mặt.","Viết để kiện cáo ra tòa án."]', 'Viết cho một người mà bạn BIẾT RÕ TÊN, có quan hệ xã giao hoặc công việc (ví dụ: Đồng nghiệp, Chủ nhà, Giáo viên, Hàng xóm) nhưng không thân thiết như bạn bè.', 'Mức độ Formal nằm ở giữa: Bạn không được suồng sã như với bạn thân, nhưng cũng không cần cứng nhắc lạnh lùng như với cơ quan nhà nước.'),
('55d5d28f-5fb9-435e-9a97-af7723d80239', 'Lời chào mở đầu chuẩn mực nhất cho một bức Thư bán trang trọng (Semi-formal) là gì?', 'multiple_choice', '["Hi bro,","Dear Sir/Madam,","Dear Mr./Mrs./Ms. [Họ của người nhận],","To all concerned,"]', 'Dear Mr./Mrs./Ms. [Họ của người nhận],', 'Vì bạn biết tên họ (ví dụ thầy giáo Smith, chủ nhà Jones), bạn phải dùng chức danh + Họ (Last name). Dùng ''Dear Sir/Madam'' là sai bối cảnh vì nó dành cho người chưa biết tên.'),
('55d5d28f-5fb9-435e-9a97-af7723d80239', 'Trong thư bán trang trọng xin lỗi sếp vì đến trễ cuộc họp, câu nào sau đây có ''Tone'' (Giọng điệu) phù hợp nhất?', 'multiple_choice', '["Sorry I was late, traffic was crazy!","I am writing to express my deepest and most profound apologies for my unpunctuality...","Please accept my apologies for arriving late to the meeting. I had an unexpected issue with my car.","My bad for being late."]', 'Please accept my apologies for arriving late to the meeting. I had an unexpected issue with my car.', 'Câu 3 giữ được sự tôn trọng, rõ ràng nhưng không bị ''làm quá'' kịch tính như câu 2, và cũng không suồng sã kiểu đường phố như câu 1 và 4.');